+    // ── Summary fields ──────────────────────────────────────────────
+
+    #[test]
+    fn summary_initial_state() {
+        let monitor = AllocationBudget::new(BudgetConfig {
+            mu_0: 25.0,
+            ..Default::default()
+        });
+        let summary = monitor.summary();
+        assert_eq!(summary.frames, 0);
