+    #[test]
+    fn budget_summary_clone_debug() {
+        let summary = BudgetSummary {
+            frames: 10,
+            total_alerts: 1,
+            e_value: 2.5,
+            cusum_plus: 3.0,
+            cusum_minus: 1.0,
+            running_mean: 55.0,
+            mu_0: 50.0,
+            drift: 5.0,
+        };
+        let cloned = summary.clone();
+        assert_eq!(cloned.frames, 10);
+        assert!((cloned.drift - 5.0).abs() < f64::EPSILON);
+        let dbg = format!("{:?}", summary);
+        assert!(dbg.contains("BudgetSummary"));
+    }
+
